Template_Code:
classDiagram
    class Grid {
        +int dimX
        +int dimY
        +launch()
    }
    class Block {
        +int blockIdx
        +SharedMemory smem
        +sync()
    }
    class Warp {
        +int warpId
        +32 threads
        +execute()
    }
    Grid "1" --> "*" Block
    Block "1" --> "*" Warp
